.darma-loader-cssloaders-github-20 {
  display: inline-block;
  width: 36px;
  height: 36px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #f97316), var(--loader-secondary-color, #fed7aa));
  animation: darma-loader-cssloaders-github-20-squareFlip 0.85s cubic-bezier(.55,.08,.38,.97) infinite;
}
@keyframes darma-loader-cssloaders-github-20-squareFlip { 0% { transform: perspective(120px) rotateX(0) rotateY(0); } 50% { transform: perspective(120px) rotateX(-180deg) rotateY(0); } 100% { transform: perspective(120px) rotateX(-180deg) rotateY(-180deg); } }

